mapper.select:
SELECT * FROM ( SELECT a.*, ROWNUM as rnum FROM ( SELECT p.POST_ID AS postId, p.BOARD_ID AS boardId, p.TITLE AS title, p.CONTENT AS content, p.CREATED_AT AS createdAt, p.CREATED_BY AS createdBy, p.VIEW_COUNT AS viewCount, u.USER_NAME AS userName FROM POST p LEFT JOIN USERS u ON p.CREATED_BY = u.USER_ID WHERE p.BOARD_ID = #{boardId}
AND TRUNC(p.CREATED_AT) >= TO_DATE(#{searchDTO.startDate}, 'YYYY-MM-DD')
AND TRUNC(p.CREATED_AT) <= TO_DATE(#{searchDTO.endDate}, 'YYYY-MM-DD')
AND p.TITLE LIKE '%' || #{searchDTO.keyword} || '%'
AND u.USER_NAME LIKE '%' || #{searchDTO.keyword} || '%'
ORDER BY NVL(p.VIEW_COUNT, 0) DESC, p.CREATED_AT DESC
ORDER BY p.CREATED_AT DESC
) a WHERE ROWNUM <= #{end} ) WHERE rnum >= #{start}

mapper.delete:
DELETE FROM attach_file
WHERE connect_address = #{postId}
AND file_id = #{fileId}
AND file_code = 'f008'
